import React, { useState } from 'react';
import { useWallet } from '../contexts/WalletContext';
import { useChat } from '../contexts/ChatContext';
import { 
  User, 
  Wallet, 
  Crown, 
  MessageSquare,
  Star,
  Copy,
  ExternalLink,
  Edit3,
  Save,
  X,
  Camera,
  Trash2,
  AlertTriangle
} from 'lucide-react';

const Profile = () => {
  const { walletAddress, ownedNFTs, userProfile, updateProfile } = useWallet();
  const { chatRooms, mintedMessages, removeMintedMessage, deleteRoom } = useChat();
  const [isEditing, setIsEditing] = useState(false);
  const [editForm, setEditForm] = useState(userProfile);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(null);
  const [deleteType, setDeleteType] = useState(null); // 'room' or 'message'

  const formatAddress = (address) => {
    return `${address.slice(0, 6)}...${address.slice(-4)}`;
  };

  const copyToClipboard = (text) => {
    navigator.clipboard.writeText(text);
    // You could add a toast notification here
  };

  const handleEditProfile = () => {
    setEditForm(userProfile);
    setIsEditing(true);
  };

  const handleSaveProfile = () => {
    updateProfile(editForm);
    setIsEditing(false);
  };

  const handleCancelEdit = () => {
    setEditForm(userProfile);
    setIsEditing(false);
  };

  const handleInputChange = (field, value) => {
    setEditForm(prev => ({ ...prev, [field]: value }));
  };

  const accessibleRooms = chatRooms.filter(room => room.hasAccess);
  const createdRooms = chatRooms.filter(room => room.createdBy === walletAddress);
  const joinedRooms = chatRooms.filter(room => room.hasAccess && room.createdBy !== walletAddress);

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div className="flex items-center space-x-4">
          <div className="relative">
            {userProfile.avatar ? (
              <img 
                src={userProfile.avatar} 
                alt="Profile" 
                className="w-16 h-16 rounded-full object-cover"
              />
            ) : (
              <div className="w-16 h-16 bg-primary-100 rounded-full flex items-center justify-center">
                <User className="w-8 h-8 text-primary-600" />
              </div>
            )}
            {isEditing && (
              <button className="absolute -bottom-1 -right-1 w-6 h-6 bg-primary-600 rounded-full flex items-center justify-center text-white hover:bg-primary-700">
                <Camera className="w-3 h-3" />
              </button>
            )}
          </div>
          <div>
            <h1 className="text-2xl font-bold text-gray-900">
              {userProfile.displayName || formatAddress(walletAddress)}
            </h1>
            <p className="text-gray-600">
              {userProfile.bio || 'Manage your DeChat account'}
            </p>
          </div>
        </div>
        
        <div className="flex space-x-2">
          {isEditing ? (
            <>
              <button
                onClick={handleSaveProfile}
                className="btn-primary flex items-center space-x-2"
              >
                <Save className="w-4 h-4" />
                <span>Save</span>
              </button>
              <button
                onClick={handleCancelEdit}
                className="btn-secondary flex items-center space-x-2"
              >
                <X className="w-4 h-4" />
                <span>Cancel</span>
              </button>
            </>
          ) : (
            <button
              onClick={handleEditProfile}
              className="btn-primary flex items-center space-x-2"
            >
              <Edit3 className="w-4 h-4" />
              <span>Edit Profile</span>
            </button>
          )}
        </div>
      </div>

      {/* Profile Edit Form */}
      {isEditing && (
        <div className="card">
          <h2 className="text-lg font-semibold text-gray-900 mb-4">Edit Profile</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Display Name
              </label>
              <input
                type="text"
                value={editForm.displayName}
                onChange={(e) => handleInputChange('displayName', e.target.value)}
                placeholder="Your display name"
                className="input-field"
              />
            </div>
            
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Location
              </label>
              <input
                type="text"
                value={editForm.location}
                onChange={(e) => handleInputChange('location', e.target.value)}
                placeholder="Your location"
                className="input-field"
              />
            </div>
            
            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Bio
              </label>
              <textarea
                value={editForm.bio}
                onChange={(e) => handleInputChange('bio', e.target.value)}
                placeholder="Tell us about yourself..."
                rows={3}
                className="input-field resize-none"
              />
            </div>
            
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Website
              </label>
              <input
                type="url"
                value={editForm.website}
                onChange={(e) => handleInputChange('website', e.target.value)}
                placeholder="https://yourwebsite.com"
                className="input-field"
              />
            </div>
            
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Twitter
              </label>
              <input
                type="text"
                value={editForm.twitter}
                onChange={(e) => handleInputChange('twitter', e.target.value)}
                placeholder="@yourusername"
                className="input-field"
              />
            </div>
            
            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Avatar URL
              </label>
              <input
                type="url"
                value={editForm.avatar}
                onChange={(e) => handleInputChange('avatar', e.target.value)}
                placeholder="https://example.com/avatar.jpg"
                className="input-field"
              />
            </div>
          </div>
        </div>
      )}

      {/* Wallet Info */}
      <div className="card">
        <h2 className="text-lg font-semibold text-gray-900 mb-4">Wallet Information</h2>
        <div className="space-y-4">
          <div className="flex items-center justify-between p-4 bg-gray-50 rounded-lg">
            <div className="flex items-center space-x-3">
              <Wallet className="w-5 h-5 text-gray-600" />
              <div>
                <p className="text-sm font-medium text-gray-900">Wallet Address</p>
                <p className="text-sm text-gray-600">{walletAddress}</p>
              </div>
            </div>
            <button
              onClick={() => copyToClipboard(walletAddress)}
              className="p-2 text-gray-400 hover:text-gray-600 rounded-lg hover:bg-gray-100 transition-colors duration-200"
            >
              <Copy className="w-4 h-4" />
            </button>
          </div>
        </div>
      </div>

      {/* Statistics */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <div className="card text-center">
          <Crown className="w-8 h-8 text-yellow-500 mx-auto mb-2" />
          <p className="text-2xl font-bold text-gray-900">{ownedNFTs.length}</p>
          <p className="text-sm text-gray-600">Owned NFTs</p>
        </div>

        <div className="card text-center">
          <MessageSquare className="w-8 h-8 text-blue-500 mx-auto mb-2" />
          <p className="text-2xl font-bold text-gray-900">{accessibleRooms.length}</p>
          <p className="text-sm text-gray-600">Accessible Rooms</p>
        </div>

        <div className="card text-center">
          <Star className="w-8 h-8 text-purple-500 mx-auto mb-2" />
          <p className="text-2xl font-bold text-gray-900">{mintedMessages.length}</p>
          <p className="text-sm text-gray-600">Minted Messages</p>
        </div>

        <div className="card text-center">
          <User className="w-8 h-8 text-green-500 mx-auto mb-2" />
          <p className="text-2xl font-bold text-gray-900">
            {chatRooms.reduce((sum, room) => sum + (room.hasAccess ? room.memberCount : 0), 0)}
          </p>
          <p className="text-sm text-gray-600">Community Size</p>
        </div>
      </div>

      {/* Owned NFTs */}
      <div className="card">
        <h2 className="text-lg font-semibold text-gray-900 mb-4">Your NFT Collection</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {ownedNFTs.map((nft) => (
            <div key={nft.id} className="border border-gray-200 rounded-lg p-4 hover:shadow-md transition-shadow duration-200">
              <img
                src={nft.image}
                alt={nft.name}
                className="w-full h-40 object-cover rounded-lg mb-3"
              />
              <h3 className="font-medium text-gray-900 mb-1">{nft.name}</h3>
              <p className="text-sm text-gray-600 mb-1">{nft.collection}</p>
              <p className="text-xs text-gray-500 mb-3">Token ID: {nft.tokenId}</p>
              <button className="w-full flex items-center justify-center space-x-2 text-sm text-primary-600 hover:text-primary-700 transition-colors duration-200">
                <ExternalLink className="w-4 h-4" />
                <span>View on OpenSea</span>
              </button>
            </div>
          ))}
        </div>
      </div>

      {/* Created Rooms */}
      {createdRooms.length > 0 && (
        <div className="card">
          <h2 className="text-lg font-semibold text-gray-900 mb-4">Rooms You Created</h2>
          <div className="space-y-3">
            {createdRooms.map((room) => (
              <div key={room.id} className="flex items-center justify-between p-3 bg-blue-50 rounded-lg border border-blue-200">
                <div>
                  <div className="flex items-center space-x-2 mb-1">
                    <h3 className="font-medium text-gray-900">{room.name}</h3>
                    <span className="text-xs bg-blue-100 text-blue-700 px-2 py-1 rounded-full">Creator</span>
                  </div>
                  <p className="text-sm text-gray-600">{room.memberCount} members</p>
                  <p className="text-xs text-gray-500">Created: {room.createdAt?.toLocaleDateString()}</p>
                </div>
                <div className="flex items-center space-x-2">
                  {room.isActive && (
                    <div className="w-2 h-2 bg-green-400 rounded-full animate-pulse"></div>
                  )}
                  <span className="text-sm text-gray-500">
                    {room.isActive ? 'Active' : 'Inactive'}
                  </span>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Joined Rooms */}
      {joinedRooms.length > 0 && (
        <div className="card">
          <h2 className="text-lg font-semibold text-gray-900 mb-4">Rooms You Joined</h2>
          <div className="space-y-3">
            {joinedRooms.map((room) => (
              <div key={room.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                <div>
                  <h3 className="font-medium text-gray-900">{room.name}</h3>
                  <p className="text-sm text-gray-600">{room.memberCount} members</p>
                  <p className="text-xs text-gray-500">Required NFT: {room.requiredNFT || 'None'}</p>
                </div>
                <div className="flex items-center space-x-2">
                  {room.isActive && (
                    <div className="w-2 h-2 bg-green-400 rounded-full animate-pulse"></div>
                  )}
                  <span className="text-sm text-gray-500">
                    {room.isActive ? 'Active' : 'Inactive'}
                  </span>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Minted Messages */}
      <div className="card">
        <h2 className="text-lg font-semibold text-gray-900 mb-4">Minted Messages as NFTs</h2>
        <div className="space-y-4">
          {mintedMessages.map((message) => (
            <div key={message.id} className="border border-gray-200 rounded-lg p-4">
              <div className="flex items-start justify-between mb-2">
                <div className="flex-1">
                  <p className="text-gray-900 mb-2">"{message.content}"</p>
                  <div className="flex items-center space-x-4 text-sm text-gray-500">
                    <span>Token ID: {message.tokenId}</span>
                    <span>•</span>
                    <span>Room: {message.room}</span>
                    <span>•</span>
                    <span>Minted: {message.mintDate.toLocaleDateString()}</span>
                  </div>
                </div>
                <button className="flex items-center space-x-1 text-sm text-primary-600 hover:text-primary-700 transition-colors duration-200">
                  <ExternalLink className="w-4 h-4" />
                  <span>View NFT</span>
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Profile;
